export type SolansPluginPdas = {
  config: typeof findConfigPda;
  stakePool: typeof findStakePoolPda;
  stakeAccount: typeof findStakeAccountPda;
  metadata: typeof findMetadataPda;
  masterEdition: typeof findMasterEditionPda;
  nameRecord: typeof findNameRecordPda;
  reverseRecord: typeof findReverseRecordPda;
};

export type SolansPluginRequirements = ClientWithRpc<
  GetAccountInfoApi & GetMultipleAccountsApi
> &
  ClientWithPayer &
  ClientWithTransactionPlanning &
  ClientWithTransactionSending;

export function solansProgram() {
  return <T extends SolansPluginRequirements>(
    client: T,
  ): ExtendedClient<T, { solans: SolansPlugin }> => {
    return extendClient(client, {
      solans: <SolansPlugin>{
        accounts: {
          auction: addSelfFetchFunctions(client, getAuctionCodec()),
          config: addSelfFetchFunctions(client, getConfigCodec()),
          listing: addSelfFetchFunctions(client, getListingCodec()),
          nameRecord: addSelfFetchFunctions(client, getNameRecordCodec()),
          offer: addSelfFetchFunctions(client, getOfferCodec()),
          reverseRecord: addSelfFetchFunctions(client, getReverseRecordCodec()),
          stakeAccount: addSelfFetchFunctions(client, getStakeAccountCodec()),
          stakePool: addSelfFetchFunctions(client, getStakePoolCodec()),
        },
        instructions: {
          acceptOffer: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getAcceptOfferInstructionAsync(input),
            ),
          autoRenew: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getAutoRenewInstructionAsync(input),
            ),
          bid: (input) =>
            addSelfPlanAndSendFunctions(client, getBidInstruction(input)),
          burnName: (input) =>
            addSelfPlanAndSendFunctions(client, getBurnNameInstruction(input)),
          buyName: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getBuyNameInstructionAsync(input),
            ),
          buybackBurn: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getBuybackBurnInstructionAsync(input),
            ),
          cancelAuction: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getCancelAuctionInstruction(input),
            ),
          cancelListing: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getCancelListingInstruction(input),
            ),
          cancelOffer: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getCancelOfferInstruction(input),
            ),
          claimExpired: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getClaimExpiredInstructionAsync(input),
            ),
          claimRewards: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getClaimRewardsInstructionAsync(input),
            ),
          initBurnPool: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getInitBurnPoolInstructionAsync(input),
            ),
          initConfig: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getInitConfigInstructionAsync(input),
            ),
          initStakePool: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getInitStakePoolInstructionAsync(input),
            ),
          listName: (input) =>
            addSelfPlanAndSendFunctions(client, getListNameInstruction(input)),
          lockTransfer: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getLockTransferInstruction(input),
            ),
          makeOffer: (input) =>
            addSelfPlanAndSendFunctions(client, getMakeOfferInstruction(input)),
          redeemName: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getRedeemNameInstructionAsync(input),
            ),
          registerName: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getRegisterNameInstructionAsync({
                ...input,
                payer: input.payer ?? client.payer,
              }),
            ),
          registerWithSolans: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getRegisterWithSolansInstructionAsync({
                ...input,
                payer: input.payer ?? client.payer,
              }),
            ),
          renewName: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getRenewNameInstructionAsync({
                ...input,
                payer: input.payer ?? client.payer,
              }),
            ),
          renewWithSolans: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getRenewWithSolansInstructionAsync({
                ...input,
                payer: input.payer ?? client.payer,
              }),
            ),
          resolve: (input) =>
            addSelfPlanAndSendFunctions(client, getResolveInstruction(input)),
          revokeSubdomain: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getRevokeSubdomainInstruction(input),
            ),
          setController: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getSetControllerInstruction(input),
            ),
          setHosting: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getSetHostingInstruction(input),
            ),
          setResolver: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getSetResolverInstruction(input),
            ),
          setReverse: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getSetReverseInstructionAsync(input),
            ),
          setSolansParams: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getSetSolansParamsInstructionAsync(input),
            ),
          settleAuction: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getSettleAuctionInstructionAsync(input),
            ),
          stake: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getStakeInstructionAsync(input),
            ),
          startAuction: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getStartAuctionInstructionAsync(input),
            ),
          tokenizeName: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getTokenizeNameInstructionAsync(input),
            ),
          transferAdmin: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getTransferAdminInstructionAsync(input),
            ),
          transferName: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getTransferNameInstruction(input),
            ),
          unstake: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getUnstakeInstructionAsync(input),
            ),
          updateConfig: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getUpdateConfigInstructionAsync(input),
            ),
          updateListing: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getUpdateListingInstruction(input),
            ),
          updateRecord: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getUpdateRecordInstruction(input),
            ),
          wrapSubdomain: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getWrapSubdomainInstructionAsync(input),
            ),
        },
        pdas: {
          config: findConfigPda,
          stakePool: findStakePoolPda,
          stakeAccount: findStakeAccountPda,
          metadata: findMetadataPda,
          masterEdition: findMasterEditionPda,
          nameRecord: findNameRecordPda,
          reverseRecord: findReverseRecordPda,
        },
        identifyAccount: identifySolansAccount,
        identifyInstruction: identifySolansInstruction,
        parseInstruction: parseSolansInstruction,
      },
    });
  };
}

type MakeOptional<T, K extends keyof T> = Omit<T, K> & Partial<Pick<T, K>>;
